const GITHUB_GROUPS = [
    {
        label: "College Thesis Capstone",
        users: ["raecellann", "Wesmabe1129", "zjdelossantos"]
    },
    {
        label: "Threads Clone",
        users: ["johnpaul-bodino", "DietherPano", "Genniesysbracia", "Nahiwagaan"]
    },
    {
        label: "Internship",
        users: ["JabbyAlicante", "beatricecoleene", "sudonotrey", "Haimonmon", "lykhasalustiano", "DietherPano"]
    }
];

// Flat unique list for fetching + sidebar
const GITHUB_USERS = [...new Set(GITHUB_GROUPS.flatMap(g => g.users))];

const CACHE_KEY = "github_users_cache_v2";
const CACHE_TTL = 1000 * 60 * 60 * 24; // 1 day

function getCache() {
    try {
        const raw = localStorage.getItem(CACHE_KEY);
        if (!raw) return null;
        const { data, timestamp } = JSON.parse(raw);
        if (Date.now() - timestamp > CACHE_TTL) {
            localStorage.removeItem(CACHE_KEY);
            return null;
        }
        return data;
    } catch {
        return null;
    }
}

function setCache(data) {
    localStorage.setItem(CACHE_KEY, JSON.stringify({ data, timestamp: Date.now() }));
}

function createCollabCard(user) {
    return `
        <div class="collab-card">
            <img class="collab-avatar" src="${user.avatar_url}" alt="${user.name || user.login}">
            <div class="collab-info">
                <span class="collab-name">${user.name || user.login}</span>
                <span class="collab-stat">${user.followers.toLocaleString()} Followers</span>
                <span class="collab-stat">${user.following.toLocaleString()} Following</span>
            </div>
            <a class="collab-visit" href="${user.html_url}" target="_blank" rel="noopener noreferrer">
                <svg xmlns="http://www.w3.org/2000/svg" width="13" height="13" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
                    <path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"/>
                    <polyline points="15 3 21 3 21 9"/>
                    <line x1="10" y1="14" x2="21" y2="3"/>
                </svg>
                Visit
            </a>
        </div>
    `;
}

function skeletonCards(count) {
    return Array.from({ length: count }, () => `
        <div class="collab-card collab-skeleton">
            <div class="skeleton-avatar"></div>
            <div class="collab-info">
                <div class="skeleton-line" style="width:70%"></div>
                <div class="skeleton-line" style="width:50%"></div>
                <div class="skeleton-line" style="width:50%"></div>
            </div>
        </div>
    `).join("");
}

function renderCards(profileMap) {
    const grid = document.getElementById("collaborators-grid");
    const gridFull = document.getElementById("collaborators-grid-full");

    // Sidebar: first 3 unique users
    if (grid) {
        const sidebarCards = GITHUB_USERS.slice(0, 3)
            .map(u => profileMap[u] ? createCollabCard(profileMap[u]) : "")
            .join("");
        grid.innerHTML = sidebarCards;
    }

    // Full page: grouped
    if (gridFull) {
        gridFull.innerHTML = GITHUB_GROUPS.map(group => `
            <div class="collab-group">
                <h3 class="collab-group-label">— ${group.label}</h3>
                <div class="collab-group-grid">
                    ${group.users.map(u =>
                        profileMap[u] ? createCollabCard(profileMap[u]) : `<div class="collab-card collab-error">Failed to load</div>`
                    ).join("")}
                </div>
            </div>
        `).join("");
    }
}

async function renderGithubUsers() {
    const grid = document.getElementById("collaborators-grid");
    const gridFull = document.getElementById("collaborators-grid-full");

    // Check cache first
    const cached = getCache();
    if (cached) {
        renderCards(cached);
        return;
    }

    // Show skeletons while fetching
    if (grid) grid.innerHTML = skeletonCards(3);
    if (gridFull) gridFull.innerHTML = skeletonCards(GITHUB_USERS.length);

    const results = await Promise.allSettled(
        GITHUB_USERS.map(username =>
            fetch(`https://api.github.com/users/${username}`).then(r => r.json())
        )
    );

    // Build username → profile map
    const profileMap = {};
    results.forEach((result, i) => {
        if (result.status === "fulfilled" && result.value.avatar_url) {
            profileMap[GITHUB_USERS[i]] = result.value;
        }
    });

    setCache(profileMap);
    renderCards(profileMap);
}

renderGithubUsers();
